mapper.select:
        SELECT
        
        

        FROM homework  a

        
            
                and a.id in
                
                #{item}
                
            
            
                and a.homework_name like CONCAT('%',#{params.homeworkName},'%')
            
            
                  and a.homework_myscore >= #{params.homeworkMyscoreStart}   
            
            
                  and a.homework_myscore <= #{params.homeworkMyscoreEnd}   
            
             
                and a.homework_myscore = #{params.homeworkMyscore}
             

            
                and a.homework_types = #{params.homeworkTypes}
            
            
                and a.zujuan_types = #{params.zujuanTypes}
            
            
                  and a.homework_delete >= #{params.homeworkDeleteStart}   
            
            
                  and a.homework_delete <= #{params.homeworkDeleteEnd}   
            
             
                and a.homework_delete = #{params.homeworkDelete}
             

        
        order by a.${params.sort} ${params.order}
